import pandas as pd

def transform_dataframe(df):
    new_df = pd.DataFrame(columns=['Time since surgery', 'Patient ID', 'age', 'sex', 'procedure type'])
    for _, row in df.iterrows():
        patient_id = row['Patient ID']
        age = row['age']
        sex = row['sex']
        procedure = row['procedure type']
        for hour in range(1, 11):
            time_since_surgery = f"{hour} hour(s)"
            new_row = {'Time since surgery': time_since_surgery, 'Patient ID': patient_id, 'age': age, 'sex': sex, 'procedure type': procedure}
            for i in range(1, 11):
                new_row[f'hour {i}'] = row[f'hour {i}']
            new_df = new_df.append(new_row, ignore_index=True)
    return new_df

